import{_ as r,C as o,o as l,c as d,a3 as e,b as n,w as a,a as s,E as h,a4 as c}from"./chunks/framework.DACwFHq9.js";const k=JSON.parse('{"title":"AIO Hub AI 小说专精模块需求调查","description":"","frontmatter":{},"headers":[],"relativePath":"Plan/ai-novel-studio-investigation.md","filePath":"Plan/ai-novel-studio-investigation.md","lastUpdated":1784256987000}'),p={name:"Plan/ai-novel-studio-investigation.md"};function u(b,t,g,E,A,m){const i=o("Mermaid");return l(),d("div",null,[t[1]||(t[1]=e('<h1 id="aio-hub-ai-小说专精模块需求调查" tabindex="-1">AIO Hub AI 小说专精模块需求调查 <a class="header-anchor" href="#aio-hub-ai-小说专精模块需求调查" aria-label="Permalink to &quot;AIO Hub AI 小说专精模块需求调查&quot;">​</a></h1><blockquote><p>状态：调查完成，建议进入垂直切片验证</p><p>最后更新：2026-07-17</p><p>建议工具 ID：<code>novel-studio</code></p><p>调查范围：用户需求、竞品、模型与成本、AIO Hub 现有能力、产品边界、技术方案与 MVP</p></blockquote><h2 id="_1-结论摘要" tabindex="-1">1. 结论摘要 <a class="header-anchor" href="#_1-结论摘要" aria-label="Permalink to &quot;1. 结论摘要&quot;">​</a></h2><p><strong>建议做，但不建议从“AI 聊天 + 续写按钮”开始做。</strong></p><p>AIO Hub 已经具备模型渠道、流式请求、智能体、世界书、条目式 RAG、上下文压缩、Token 计算、文本差异和资产管理等底层能力。真正缺少的是一个以“作品项目”为中心的小说工作台，将这些能力组织为可持续的长篇创作流程。</p><p>建议产品定位：</p><blockquote><p>一个本地优先、模型开放、上下文可解释、修改可回退的 AI 小说项目工作台。</p></blockquote><p>第一版的核心价值不是“自动写整本书”，而是同时解决四件事：</p><ol><li><strong>结构管理</strong>：作品、卷、章、场景、大纲、伏笔和人物关系不再散落在聊天记录里。</li><li><strong>上下文管理</strong>：每次生成都能知道模型收到了什么、为什么收到、花了多少 Token。</li><li><strong>非破坏式协作</strong>：AI 提供候选、差异和建议，不能静默覆盖正文。</li><li><strong>多模型成本控制</strong>：规划、正文、摘要、审校分别绑定模型，旗舰模型只处理高价值任务。</li></ol><p>综合判断：</p><table tabindex="0"><thead><tr><th>维度</th><th>判断</th><th>说明</th></tr></thead><tbody><tr><td>用户需求</td><td>强</td><td>长篇创作天然存在结构、记忆、版本和连续性问题；转发讨论也直接出现“主模型生产 + 副模型审校”的工作流诉求</td></tr><tr><td>市场验证</td><td>已验证</td><td>Novelcrafter、Sudowrite、NovelAI、阅文作家助手、FeelFish、百度作家平台均已覆盖部分需求</td></tr><tr><td>AIO 适配度</td><td>高</td><td>现有模型基础设施和内容工具可明显降低开发成本，并形成 BYOK、本地存储、可观测性的差异化</td></tr><tr><td>技术风险</td><td>中等</td><td>难点主要在长篇上下文、正文版本、结构化事实同步和编辑器交互，不在模型 API 接入</td></tr><tr><td>商业风险</td><td>中等</td><td>竞品较多；如果只做生成按钮没有竞争力，必须突出开放模型、本地项目、上下文审计和工作流可定制</td></tr><tr><td>建议</td><td><strong>Go，先做垂直切片</strong></td><td>用一个可写 3-5 章真实作品的最小闭环验证，不先做自动代理团队、协作和出版平台接入</td></tr></tbody></table><h2 id="_2-需求来源与判断边界" tabindex="-1">2. 需求来源与判断边界 <a class="header-anchor" href="#_2-需求来源与判断边界" aria-label="Permalink to &quot;2. 需求来源与判断边界&quot;">​</a></h2><p>本次需求由一段关于 Kimi 重度使用、小说创作和“主模型生产 + 副模型审校”的社区讨论触发。该讨论可作为<strong>定性需求信号</strong>，不能作为价格、额度或模型能力的可靠基线。</p><p>尤其需要区分：</p><ul><li><strong>消费者会员/Coding Plan</strong>：额度、用途、风控和产品入口可能频繁变化，通常不能直接被 AIO Hub 调用。</li><li><strong>开放平台 API</strong>：有明确的 Token 计费和调用契约，才是 AIO Hub 可长期集成的基础。</li><li><strong>第三方聚合渠道</strong>：可以作为用户自选 Profile，但模块不能依赖某个渠道的临时套餐经济性。</li></ul><p>因此，<code>novel-studio</code> 应绑定 AIO 已有的 LLM Profile/Model，而不是内置“购买 Kimi 199/699 套餐”之类的产品假设。</p><h2 id="_3-目标用户与核心任务" tabindex="-1">3. 目标用户与核心任务 <a class="header-anchor" href="#_3-目标用户与核心任务" aria-label="Permalink to &quot;3. 目标用户与核心任务&quot;">​</a></h2><h3 id="_3-1-主要用户" tabindex="-1">3.1 主要用户 <a class="header-anchor" href="#_3-1-主要用户" aria-label="Permalink to &quot;3.1 主要用户&quot;">​</a></h3><p>第一阶段建议只服务两类用户：</p><ol><li><p><strong>中文网文/连载作者</strong></p><ul><li>高频更新，重视章纲、节奏、钩子、设定一致性和前文回溯。</li><li>对生成成本敏感，愿意混用模型。</li><li>常见作品体量远超单次模型上下文，不可能靠“全文塞进去”解决。</li></ul></li><li><p><strong>中长篇类型小说作者</strong></p><ul><li>重视人物弧、场景、伏笔、视角、文风和多轮修订。</li><li>需要规划派和探索派两种工作模式。</li><li>更在意版本、审校和创作控制权，而非单纯日更速度。</li></ul></li></ol><p>暂不把多人编辑、出版社流程、剧本和非虚构写作列为 MVP 目标。</p><h3 id="_3-2-用户真正要完成的任务" tabindex="-1">3.2 用户真正要完成的任务 <a class="header-anchor" href="#_3-2-用户真正要完成的任务" aria-label="Permalink to &quot;3.2 用户真正要完成的任务&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>用户任务</th><th>当前通用聊天的主要问题</th></tr></thead><tbody><tr><td>构思</td><td>把点子扩展为题材、卖点、人物、冲突和结局方向</td><td>输出散落在对话中，无法形成可维护结构</td></tr><tr><td>规划</td><td>建立卷纲、章纲、场景节拍、人物弧和伏笔</td><td>结构修改后，旧对话和旧设定不会同步</td></tr><tr><td>起草</td><td>根据当前场景目标生成或协写正文</td><td>模型容易忘记视角、时间、人物状态和未解决线索</td></tr><tr><td>修订</td><td>重写局部、控制语气、扩写/压缩、比较候选</td><td>通用聊天以整段替换为主，接受粒度太粗</td></tr><tr><td>审校</td><td>检查连续性、重复、节奏、角色声音和设定冲突</td><td>只给泛泛评价，问题无法定位到正文和事实来源</td></tr><tr><td>连载</td><td>快速回忆前文、维护章纲、生成本章钩子</td><td>上下文成本随章节线性增长，且摘要逐轮漂移</td></tr><tr><td>交付</td><td>导出干净正文、项目备份和生成记录</td><td>聊天记录不是作品文件，迁移和回退困难</td></tr></tbody></table><h3 id="_3-3-必须解决的高频痛点" tabindex="-1">3.3 必须解决的高频痛点 <a class="header-anchor" href="#_3-3-必须解决的高频痛点" aria-label="Permalink to &quot;3.3 必须解决的高频痛点&quot;">​</a></h3><ul><li><strong>长篇失忆</strong>：人物状态、物品归属、时间线和伏笔在几十章后发生漂移。</li><li><strong>上下文黑箱</strong>：用户不知道模型遗漏了什么，也不知道昂贵模型为何消耗大量输入 Token。</li><li><strong>AI 味与同质化</strong>：套话、总结腔、形容词堆积、过度解释、对话声音趋同。</li><li><strong>结构与正文脱节</strong>：大纲改了，已写正文、章纲和人物状态没有明确的受影响提示。</li><li><strong>版本焦虑</strong>：一次重写可能破坏原文，用户不敢放手使用 AI。</li><li><strong>模型选择疲劳</strong>：规划、写作、摘要、审校对模型能力要求不同，用户却只能反复手动切换。</li><li><strong>成本不可预测</strong>：重度使用时，真正昂贵的是重复上下文、候选重生成和多轮审校，而不只是最终正文 Token。</li></ul><h2 id="_4-竞品调查" tabindex="-1">4. 竞品调查 <a class="header-anchor" href="#_4-竞品调查" aria-label="Permalink to &quot;4. 竞品调查&quot;">​</a></h2><h3 id="_4-1-竞品对比" tabindex="-1">4.1 竞品对比 <a class="header-anchor" href="#_4-1-竞品对比" aria-label="Permalink to &quot;4.1 竞品对比&quot;">​</a></h3><p>以下为 2026-07-17 官方页面可见信息；套餐和模型会变化，实施前需再次核验。</p><table tabindex="0"><thead><tr><th>产品</th><th>核心方法</th><th>代表能力</th><th>计费/模型策略</th><th>对 AIO 的启示</th></tr></thead><tbody><tr><td>Novelcrafter</td><td>作品结构 + Codex + BYOK</td><td>规划视图、角色/地点/设定 Codex、跨书共享、场景节拍生成、章节摘要、Workshop Chat、自定义提示词</td><td>平台月费 $4/$8/$14/$20；$8 起支持 BYOK，AI 费用另付</td><td>最接近 AIO 的开放模型路线；说明用户愿意为“结构与上下文层”单独付费</td></tr><tr><td>Sudowrite</td><td>封闭式小说 AI 套件</td><td>Story Bible、Write、Expand、Rewrite、Feedback、Canvas、Brainstorm、Visualize、插件</td><td>月费 $10/$22/$44，按 credits；混用 Anthropic、OpenAI、开源和自研 Muse</td><td>原子写作动作和编辑体验比聊天更重要；“小说专用模型 + 专有前后处理”是其壁垒</td></tr><tr><td>NovelAI</td><td>无限文本生成 + 记忆层</td><td>写作助手、分档 Memory、TTS、自有/开源叙事模型</td><td>Writer 套餐 $10/$15/$25；官方页标注无限文本生成，记忆约 8K/12K/28K Token</td><td>用户也接受“模型与产品打包”；AIO 不宜与其拼无限额度，应拼开放性和项目控制</td></tr><tr><td>阅文作家助手</td><td>网文生产与平台生态</td><td>存稿导入/加密、模板中心、读者端多平台预览、章纲提取，桌面端标注集成 DeepSeek-R1</td><td>平台型工具，创作与发布生态结合</td><td>中文网文需求不止 AI；章纲回溯、读者端分段预览、日更工作流非常关键</td></tr><tr><td>FeelFish</td><td>小说智能体 + 多模型</td><td>角色/设定、智能上下文、技能、知识库、多智能体、DeepSeek/千问</td><td>免费及 ¥17/¥35/¥119 月费，按积分；官方示例称 1 亿积分用 DeepSeek 约可写 10 万字</td><td>是 AIO 在中文独立客户端方向的直接竞品；仅有“智能体 + 知识库”不足以区分</td></tr><tr><td>百度作家平台</td><td>平台内 AI 生文</td><td>短篇对话生文、短篇续写、长篇章节生文、长篇拆书、章节摘要</td><td>平台内服务</td><td>“拆书 -&gt; 规划 -&gt; 连载 -&gt; 摘要”已成为中文产品的标准链路</td></tr></tbody></table><h3 id="_4-2-市场共同模式" tabindex="-1">4.2 市场共同模式 <a class="header-anchor" href="#_4-2-市场共同模式" aria-label="Permalink to &quot;4.2 市场共同模式&quot;">​</a></h3><p>竞品虽然形态不同，但共同收敛到五层：</p><ol><li><strong>作品层</strong>：书、卷、章、场景和项目文件。</li><li><strong>设定层</strong>：人物、地点、规则、物品、时间线和世界观。</li><li><strong>规划层</strong>：大纲、节拍、人物弧、伏笔和章节目标。</li><li><strong>AI 动作层</strong>：构思、续写、扩写、重写、摘要、反馈和抽取。</li><li><strong>记忆层</strong>：近期正文、滚动摘要、相关设定和可检索资料。</li></ol><p>这说明小说模块不是一个 Prompt 集合，而是一个<strong>领域数据模型 + 编辑器 + 上下文编译器</strong>。</p><h3 id="_4-3-可形成差异化的空位" tabindex="-1">4.3 可形成差异化的空位 <a class="header-anchor" href="#_4-3-可形成差异化的空位" aria-label="Permalink to &quot;4.3 可形成差异化的空位&quot;">​</a></h3><p>现有产品常在以下方向二选一：</p><ul><li>体验完整，但模型、数据和计费封闭；</li><li>模型开放，但工作流、上下文可解释性和版本控制较弱。</li></ul><p>AIO 可以组合出一条更清晰的路线：</p><ul><li>本地优先、多文件项目，可直接备份和迁移；</li><li>任意 AIO LLM Profile，支持官方 API、聚合渠道和本地模型；</li><li>按任务配置模型，而非整本书锁定一个模型；</li><li>上下文预览、来源标记、Token/费用估算和生成记录；</li><li>候选分支、段落级差异、接受/拒绝和快照回退；</li><li>世界书、知识库、资产、文本差异等 AIO 工具协同，但保持清晰的数据所有权。</li></ul><h2 id="_5-建议产品定义" tabindex="-1">5. 建议产品定义 <a class="header-anchor" href="#_5-建议产品定义" aria-label="Permalink to &quot;5. 建议产品定义&quot;">​</a></h2><h3 id="_5-1-名称与入口" tabindex="-1">5.1 名称与入口 <a class="header-anchor" href="#_5-1-名称与入口" aria-label="Permalink to &quot;5.1 名称与入口&quot;">​</a></h3><ul><li>工具 ID：<code>novel-studio</code></li><li>中文名建议：<strong>小说工坊</strong> 或 <strong>小说工作台</strong></li><li>一句话：从设定、大纲、章节到审校的本地 AI 小说项目工作台。</li></ul><h3 id="_5-2-主界面" tabindex="-1">5.2 主界面 <a class="header-anchor" href="#_5-2-主界面" aria-label="Permalink to &quot;5.2 主界面&quot;">​</a></h3><p>建议采用安静、密集、适合长时间工作的四区布局：</p><table tabindex="0"><thead><tr><th>区域</th><th>内容</th></tr></thead><tbody><tr><td>左侧项目树</td><td>卷、章、场景、状态、字数、拖拽排序、搜索</td></tr><tr><td>中央编辑器</td><td>正文、选区 AI 操作、专注模式、版本标记、字数与保存状态</td></tr><tr><td>右侧检查器</td><td><code>大纲</code>、<code>设定</code>、<code>AI</code>、<code>审校</code> 四个 Tab，随当前章节/场景联动</td></tr><tr><td>底部状态区</td><td>当前模型角色、上下文 Token、预计费用、生成状态、问题数量</td></tr></tbody></table><p>不要把核心体验做成卡片首页或聊天首页。打开工具后应直接进入最近作品的编辑状态。</p><h3 id="_5-3-领域对象" tabindex="-1">5.3 领域对象 <a class="header-anchor" href="#_5-3-领域对象" aria-label="Permalink to &quot;5.3 领域对象&quot;">​</a></h3><p>MVP 建议至少定义以下对象：</p><ul><li><code>NovelProject</code>：作品元信息、题材、目标读者、总纲、默认语言。</li><li><code>Volume</code> / <code>Chapter</code> / <code>Scene</code>：稳定 ID、顺序、状态、目标、摘要和正文引用。</li><li><code>StoryEntity</code>：人物、地点、组织、物品、规则等统一实体，支持类型扩展。</li><li><code>StoryFact</code>：带来源和有效时间范围的事实，例如“第 12 章后左臂受伤”。</li><li><code>StoryBeat</code>：场景目标、冲突、转折、结果和未解决问题。</li><li><code>Foreshadowing</code>：埋设位置、计划回收位置、状态和相关实体。</li><li><code>StyleProfile</code>：视角、时态、句长倾向、禁用表达、示例片段。</li><li><code>ChapterSummary</code>：结构化摘要，是派生数据，保留生成来源和版本。</li><li><code>GenerationRun</code>：任务、模型、Prompt 版本、上下文清单、Token、费用、候选和接受结果。</li><li><code>ManuscriptSnapshot</code>：正文快照或增量补丁，用于非破坏式回退。</li><li><code>NovelModelRoleBinding</code>：模型角色到 AIO Profile/Model/参数的映射。</li></ul><h3 id="_5-4-模型角色" tabindex="-1">5.4 模型角色 <a class="header-anchor" href="#_5-4-模型角色" aria-label="Permalink to &quot;5.4 模型角色&quot;">​</a></h3><p>论坛中的“主模型 + 副模型”方向正确，但产品层应抽象为任务角色，而不是写死两个模型：</p><table tabindex="0"><thead><tr><th>角色</th><th>任务</th><th>默认成本策略</th></tr></thead><tbody><tr><td><code>planner</code></td><td>题材分析、总纲、人物弧、复杂情节推演</td><td>旗舰推理模型，中低频</td></tr><tr><td><code>drafter</code></td><td>场景和正文候选</td><td>文本表现最好的模型，高频，允许用户设定思考强度</td></tr><tr><td><code>utility</code></td><td>摘要、实体/事实抽取、标签、格式整理</td><td>低成本模型，可批处理</td></tr><tr><td><code>reviewer</code></td><td>连续性、风格、节奏、重复和读者反馈</td><td>尽量与 <code>drafter</code> 不同，降低同源盲点</td></tr></tbody></table><p>所有角色都允许映射到同一个模型；默认模板只提供建议，不应硬编码“最佳模型”。</p><h2 id="_6-上下文系统" tabindex="-1">6. 上下文系统 <a class="header-anchor" href="#_6-上下文系统" aria-label="Permalink to &quot;6. 上下文系统&quot;">​</a></h2><h3 id="_6-1-基本原则" tabindex="-1">6.1 基本原则 <a class="header-anchor" href="#_6-1-基本原则" aria-label="Permalink to &quot;6.1 基本原则&quot;">​</a></h3><p>长上下文窗口不能替代上下文工程。即使模型支持 1M Token，把整本书反复发送仍会带来成本、注意力稀释和不可解释性。</p><p>建议每次请求由 <code>NovelContextCompiler</code> 根据任务编译上下文：</p>',56)),(l(),n(c,null,{default:a(()=>[h(i,{id:"mermaid-815",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22%E5%BD%93%E5%89%8D%E4%BB%BB%E5%8A%A1%E4%B8%8E%E9%80%89%E5%8C%BA%22%5D%20--%3E%20H%5B%22%E4%B8%8A%E4%B8%8B%E6%96%87%E7%BC%96%E8%AF%91%E5%99%A8%22%5D%0A%20%20%20%20B%5B%22%E4%BD%9C%E5%93%81%E8%A7%84%E5%88%99%E4%B8%8E%E6%96%87%E9%A3%8E%22%5D%20--%3E%20H%0A%20%20%20%20C%5B%22%E5%BD%93%E5%89%8D%E7%AB%A0%E7%BA%B2%E4%B8%8E%E5%9C%BA%E6%99%AF%E8%8A%82%E6%8B%8D%22%5D%20--%3E%20H%0A%20%20%20%20D%5B%22%E8%BF%91%E6%9C%9F%E6%AD%A3%E6%96%87%22%5D%20--%3E%20H%0A%20%20%20%20E%5B%22%E6%BB%9A%E5%8A%A8%E6%91%98%E8%A6%81%22%5D%20--%3E%20H%0A%20%20%20%20F%5B%22%E7%9B%B8%E5%85%B3%E4%BA%BA%E7%89%A9%2F%E5%9C%B0%E7%82%B9%2F%E4%BA%8B%E5%AE%9E%22%5D%20--%3E%20H%0A%20%20%20%20G%5B%22%E4%BC%8F%E7%AC%94%E4%B8%8E%E6%97%B6%E9%97%B4%E7%BA%BF%22%5D%20--%3E%20H%0A%20%20%20%20H%20--%3E%20I%5B%22Token%20%E9%A2%84%E7%AE%97%E4%B8%8E%E5%8E%BB%E9%87%8D%22%5D%0A%20%20%20%20I%20--%3E%20J%5B%22%E5%8F%AF%E9%A2%84%E8%A7%88%E8%AF%B7%E6%B1%82%22%5D%0A%20%20%20%20J%20--%3E%20K%5B%22%E6%A8%A1%E5%9E%8B%E7%94%9F%E6%88%90%22%5D%0A%20%20%20%20K%20--%3E%20L%5B%22%E5%80%99%E9%80%89%2F%E5%B7%AE%E5%BC%82%2F%E5%AE%A1%E6%A0%A1%E7%BB%93%E6%9E%9C%22%5D%0A%20%20%20%20L%20--%3E%20M%5B%22%E7%94%A8%E6%88%B7%E6%8E%A5%E5%8F%97%E5%90%8E%E5%86%99%E5%85%A5%E6%AD%A3%E6%96%87%22%5D%0A%20%20%20%20L%20--%3E%20N%5B%22%E7%94%9F%E6%88%90%E8%AE%B0%E5%BD%95%E4%B8%8E%E6%B4%BE%E7%94%9F%E6%91%98%E8%A6%81%22%5D%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[s(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=e(`<h3 id="_6-2-上下文优先级" tabindex="-1">6.2 上下文优先级 <a class="header-anchor" href="#_6-2-上下文优先级" aria-label="Permalink to &quot;6.2 上下文优先级&quot;">​</a></h3><p>建议按以下优先级裁剪：</p><ol><li>当前任务和用户明确选择的文本；</li><li>当前场景目标、POV、时间和地点；</li><li>被“锁定”的作品规则和事实；</li><li>直接相关人物、物品、伏笔和时间线；</li><li>最近 1-3 个场景原文；</li><li>更早章节的结构化摘要；</li><li>参考资料 RAG 结果；</li><li>低相关背景资料。</li></ol><p>每个上下文块必须带：<code>sourceType</code>、<code>sourceId</code>、<code>reason</code>、<code>priority</code>、<code>tokenCount</code>。用户应能在发送前查看、排除或固定某一块。</p><h3 id="_6-3-记忆分层" tabindex="-1">6.3 记忆分层 <a class="header-anchor" href="#_6-3-记忆分层" aria-label="Permalink to &quot;6.3 记忆分层&quot;">​</a></h3><ul><li><strong>原文记忆</strong>：近期正文，精确但昂贵。</li><li><strong>情节记忆</strong>：章/场景摘要，便宜但可能漂移。</li><li><strong>事实记忆</strong>：人物状态、地点规则、物品归属等结构化事实。</li><li><strong>语义记忆</strong>：知识库中的研究资料和远期内容，用检索召回。</li><li><strong>作者记忆</strong>：用户手动锁定的规则、禁忌和必须保留的表达。</li></ul><p>摘要和事实抽取都应记录来源版本。正文变化后将派生内容标记为 <code>stale</code>，不能悄悄继续使用旧摘要。</p><h2 id="_7-与-aio-hub-现有能力的关系" tabindex="-1">7. 与 AIO Hub 现有能力的关系 <a class="header-anchor" href="#_7-与-aio-hub-现有能力的关系" aria-label="Permalink to &quot;7. 与 AIO Hub 现有能力的关系&quot;">​</a></h2><h3 id="_7-1-可以直接复用" tabindex="-1">7.1 可以直接复用 <a class="header-anchor" href="#_7-1-可以直接复用" aria-label="Permalink to &quot;7.1 可以直接复用&quot;">​</a></h3><table tabindex="0"><thead><tr><th>现有能力</th><th>复用方式</th></tr></thead><tbody><tr><td><code>useLlmRequest</code>、LLM Profiles、KeyManager、Provider Adapters</td><td>统一模型请求、流式输出、参数过滤、网络策略和密钥轮换</td></tr><tr><td><code>@aiohub/llm-core</code></td><td>Provider 无关请求与响应语义，避免小说模块自建模型 SDK</td></tr><tr><td><code>llm-inspector</code></td><td>给 <code>GenerationRun</code> 提供请求审计和故障诊断入口</td></tr><tr><td><code>token-calculator</code></td><td>上下文 Token 预算和发送前估算</td></tr><tr><td><code>text-diff</code></td><td>候选正文与当前正文的差异预览</td></tr><tr><td><code>st-worldbook-manager</code></td><td>导入/导出 SillyTavern 世界书，以及复用部分选择器/编辑交互</td></tr><tr><td><code>knowledge-base</code></td><td>研究资料、背景知识、远期事实的检索；不把整本正文无脑切块后当唯一记忆</td></tr><tr><td><code>asset-manager</code></td><td>参考图片、地图、资料和封面等资产引用</td></tr><tr><td><code>rich-text-renderer</code></td><td>AI 审校报告、Markdown 说明和引用展示</td></tr><tr><td><code>agent-manager</code></td><td>可选的写作顾问/审校人格模板，不作为作品数据所有者</td></tr></tbody></table><h3 id="_7-2-不应直接复用的数据边界" tabindex="-1">7.2 不应直接复用的数据边界 <a class="header-anchor" href="#_7-2-不应直接复用的数据边界" aria-label="Permalink to &quot;7.2 不应直接复用的数据边界&quot;">​</a></h3><ol><li><p><strong>不要把小说正文存成 <code>llm-chat</code> 会话。</strong></p><ul><li>聊天消息树适合对话探索，不适合卷章排序、场景拆分、稳定引用和干净导出。</li><li>可以复用非破坏式分支思想，但作品正文必须有自己的存储和版本模型。</li></ul></li><li><p><strong>不要把 ST 世界书直接当小说的唯一 Canon 数据库。</strong></p><ul><li>ST 世界书偏向关键词触发和上下文注入；小说需要时间有效性、事实来源、人物状态和伏笔生命周期。</li><li>应提供双向导入/导出适配，而不是让 <code>novel-studio</code> 依赖 ST 格式语义。</li></ul></li><li><p><strong>不要让 RAG 替代结构化事实。</strong></p><ul><li>“某人现在是否受伤”需要确定性状态和来源，不应只靠相似度检索碰运气。</li></ul></li><li><p><strong>不要复制 <code>llm-chat</code> 的完整上下文管道。</strong></p><ul><li>第一版直接基于共享 LLM 请求层实现小说专用编译器；真正通用的处理器再下沉为共享包。</li></ul></li></ol><h3 id="_7-3-存储建议" tabindex="-1">7.3 存储建议 <a class="header-anchor" href="#_7-3-存储建议" aria-label="Permalink to &quot;7.3 存储建议&quot;">​</a></h3><p>该工具属于多文件关联和版本数据场景，不适合用 <code>ConfigManager</code> 保存整个项目。建议使用自定义存储层并保证原子写入：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{appConfigDir}/novel-studio/</span></span>
<span class="line"><span>  projects-index.json</span></span>
<span class="line"><span>  projects/{projectId}/</span></span>
<span class="line"><span>    project.json</span></span>
<span class="line"><span>    outline.json</span></span>
<span class="line"><span>    entities.json</span></span>
<span class="line"><span>    facts.json</span></span>
<span class="line"><span>    foreshadowing.json</span></span>
<span class="line"><span>    manuscript/{chapterId}.md</span></span>
<span class="line"><span>    summaries/{chapterId}.json</span></span>
<span class="line"><span>    snapshots/{chapterId}/...</span></span>
<span class="line"><span>    runs/{runId}.json</span></span>
<span class="line"><span>    assets/...</span></span></code></pre></div><p>正文按章拆文件，索引和正文分离；不要把整本小说、所有运行记录和版本塞进单个 JSON。</p><h2 id="_8-mvp-范围" tabindex="-1">8. MVP 范围 <a class="header-anchor" href="#_8-mvp-范围" aria-label="Permalink to &quot;8. MVP 范围&quot;">​</a></h2><h3 id="_8-1-p0-可验证垂直切片" tabindex="-1">8.1 P0：可验证垂直切片 <a class="header-anchor" href="#_8-1-p0-可验证垂直切片" aria-label="Permalink to &quot;8.1 P0：可验证垂直切片&quot;">​</a></h3><p>P0 必须形成完整闭环：</p><ul><li>新建/打开本地作品；</li><li>卷、章、场景树和拖拽排序；</li><li>Markdown/纯文本正文编辑、自动保存、字数统计；</li><li>人物/地点/规则的基础设定表；</li><li>章纲和场景节拍；</li><li>四个模型角色配置；</li><li>上下文编译与发送前预览；</li><li>“根据节拍起草”“续写”“选区重写”三种 AI 动作；</li><li>每次生成 1-3 个候选；</li><li>差异预览、按候选接受、拒绝；</li><li>章节快照和回退；</li><li>自动章节摘要与过期标记；</li><li>Markdown/TXT/项目 JSON 导出；</li><li>生成记录中的模型、Token、耗时和估算费用。</li></ul><h3 id="_8-2-p1-形成小说专精" tabindex="-1">8.2 P1：形成小说专精 <a class="header-anchor" href="#_8-2-p1-形成小说专精" aria-label="Permalink to &quot;8.2 P1：形成小说专精&quot;">​</a></h3><ul><li>连续性检查：人物状态、时间、地点、物品和规则冲突；</li><li>伏笔管理与回收提醒；</li><li>风格画像、禁用表达和角色对白声音检查；</li><li>重复用词、句式和跨章情节重复检测；</li><li>章节节奏/钩子检查；</li><li>作品导入后的拆章、摘要和实体候选抽取；</li><li>世界书和知识库适配；</li><li>自定义 AI 动作模板；</li><li>Prompt/上下文版本化和批量重跑。</li></ul><h3 id="_8-3-p2-暂缓" tabindex="-1">8.3 P2：暂缓 <a class="header-anchor" href="#_8-3-p2-暂缓" aria-label="Permalink to &quot;8.3 P2：暂缓&quot;">​</a></h3><ul><li>全自动“从大纲写完整本书”；</li><li>多智能体自治团队；</li><li>多人实时协作；</li><li>出版平台一键发布；</li><li>移动端完整编辑；</li><li>训练/微调小说专用模型；</li><li>EPUB/DOCX 精排和出版级排版。</li></ul><p>这些功能价值不低，但会掩盖 P0 最重要的问题：用户是否愿意在这个工作台里连续写完多章，并信任它的上下文和版本系统。</p><h2 id="_9-模型与成本策略" tabindex="-1">9. 模型与成本策略 <a class="header-anchor" href="#_9-模型与成本策略" aria-label="Permalink to &quot;9. 模型与成本策略&quot;">​</a></h2><h3 id="_9-1-当前官方-api-信号" tabindex="-1">9.1 当前官方 API 信号 <a class="header-anchor" href="#_9-1-当前官方-api-信号" aria-label="Permalink to &quot;9.1 当前官方 API 信号&quot;">​</a></h3><p>截至 2026-07-17：</p><ul><li>Kimi 官方文档显示 <code>kimi-k3</code> 为 1,048,576 Token 上下文，缓存命中输入 ¥2/1M、未命中输入 ¥20/1M、输出 ¥100/1M。</li><li><code>kimi-k2.6</code> 为 262,144 Token 上下文，缓存命中输入 ¥1.1/1M、未命中输入 ¥6.5/1M、输出 ¥27/1M。</li><li><code>kimi-k2.5</code> 为 262,144 Token 上下文，缓存命中输入 ¥0.7/1M、未命中输入 ¥4/1M、输出 ¥21/1M。</li><li>DeepSeek 官方文档显示 DeepSeek V4 Flash/Pro 均为 1M 上下文，输出分别为 $0.28/$0.87 每 1M Token，且缓存命中输入价格显著低于未命中。</li></ul><p>价格说明了两个产品事实：</p><ol><li>旗舰模型可以承担规划、关键正文和难题，但不该默认处理摘要、实体抽取和格式整理。</li><li>稳定前缀缓存和上下文去重不是底层小优化，而是小说模块的核心产品能力。</li></ol><h3 id="_9-2-粗略成本示例" tabindex="-1">9.2 粗略成本示例 <a class="header-anchor" href="#_9-2-粗略成本示例" aria-label="Permalink to &quot;9.2 粗略成本示例&quot;">​</a></h3><p>假设一部 30 万汉字小说，共 100 章，每章 AI 起草 3000 汉字。Kimi 文档给出的通常中文换算约为 1 Token 对应 1.5-2 个汉字：</p><ul><li>一次完整正文输出约 15-20 万 Token。</li><li>K3 仅输出费用约 ¥15-20。</li><li>若每章平均发送 2 万输入 Token，100 章为 200 万输入 Token；全部未命中缓存约 ¥40，全部按命中价计算约 ¥4。</li><li>因此 K3 单候选、单遍起草的基础量级约为 <strong>¥20-60</strong>，尚未包含多候选、规划、审校、失败重试和人工反复改写。</li><li>同样的简单任务若使用 K2.5，输出约 ¥3.2-4.2，200 万未命中输入约 ¥8。</li></ul><p>这只是为了说明量级，不是账单承诺。真实成本取决于上下文长度、缓存比例、模型输出习惯、候选数和接受率。产品中应显示：</p><ul><li>本次预计输入/输出 Token；</li><li>当前角色模型的单价配置；</li><li>本章和全项目累计消耗；</li><li><strong>每千字被接受正文的成本</strong>，而不是只统计生成成本。</li></ul><h3 id="_9-3-不做静态-模型排行榜" tabindex="-1">9.3 不做静态“模型排行榜” <a class="header-anchor" href="#_9-3-不做静态-模型排行榜" aria-label="Permalink to &quot;9.3 不做静态“模型排行榜”&quot;">​</a></h3><p>小说质量高度依赖题材、语言、提示词、审美和编辑方式。建议在工具内提供可复现的模型试写/盲评：</p><ul><li>同一场景节拍调用多个候选模型；</li><li>隐藏模型名后让用户选择；</li><li>记录接受率、人工修改比例、连续性错误、重复表达和成本；</li><li>最终推荐基于用户自己的作品数据，而不是官方宣传或社区单次体验。</li></ul><p>首个内部基准可准备 20 个中文场景，覆盖对白、动作、情绪、悬疑、信息揭示、过场、不同 POV 和长程伏笔回收。</p><h2 id="_10-安全、版权与信任" tabindex="-1">10. 安全、版权与信任 <a class="header-anchor" href="#_10-安全、版权与信任" aria-label="Permalink to &quot;10. 安全、版权与信任&quot;">​</a></h2><ul><li><strong>本地优先</strong>：正文和项目默认保存在本地；调用云模型时明确显示将发送的上下文。</li><li><strong>最小发送</strong>：附件、整章或研究资料不能在未进入上下文清单时被隐式上传。</li><li><strong>不静默覆盖</strong>：所有 AI 修改先进入候选或差异视图，用户接受后才写入正文。</li><li><strong>来源可追踪</strong>：摘要、事实和审校问题都记录对应正文版本和来源位置。</li><li><strong>隐私提示</strong>：不同模型提供商的数据政策不同，AIO 只能展示渠道信息，不能替提供商承诺不训练。</li><li><strong>版权提示</strong>：不提供“模仿在世作者”默认模板；风格画像优先描述可观察特征，而不是只写作者姓名。</li><li><strong>平台政策</strong>：不同连载/出版平台对 AI 内容标注和版权要求不同，后续可做政策说明，但不自动替用户判断合规。</li><li><strong>提示词注入</strong>：外部研究资料和导入世界书属于不可信内容，作为资料块处理，不能覆盖系统和作品规则。</li></ul><h2 id="_11-验证计划" tabindex="-1">11. 验证计划 <a class="header-anchor" href="#_11-验证计划" aria-label="Permalink to &quot;11. 验证计划&quot;">​</a></h2><h3 id="_11-1-开发前验证" tabindex="-1">11.1 开发前验证 <a class="header-anchor" href="#_11-1-开发前验证" aria-label="Permalink to &quot;11.1 开发前验证&quot;">​</a></h3><p>建议先访谈 5-8 位真实作者，至少包含 3 位有 20 万字以上作品经验的连载作者。不要只问“想要什么功能”，应让用户展示：</p><ul><li>当前目录、正文、大纲和设定如何存放；</li><li>最近一次前后文冲突如何产生；</li><li>如何用 Kimi/DeepSeek/Claude 等完成一次真实续写或审校；</li><li>哪些 AI 输出会直接丢弃；</li><li>如何备份、回滚和投稿；</li><li>每月能接受的工具费和模型费。</li></ul><h3 id="_11-2-垂直切片验收" tabindex="-1">11.2 垂直切片验收 <a class="header-anchor" href="#_11-2-垂直切片验收" aria-label="Permalink to &quot;11.2 垂直切片验收&quot;">​</a></h3><p>用一个 3-5 章、至少 1.5 万字的真实项目完成以下任务：</p><ol><li>导入已有设定和前三章；</li><li>建立第四章章纲与两个场景节拍；</li><li>使用不同 <code>planner</code>/<code>drafter</code> 模型生成候选；</li><li>查看上下文来源和费用；</li><li>接受部分候选并保留原版本；</li><li>自动生成摘要和事实候选；</li><li>在第五章触发一次前文事实召回与连续性检查；</li><li>导出干净正文和完整项目备份。</li></ol><h3 id="_11-3-核心指标" tabindex="-1">11.3 核心指标 <a class="header-anchor" href="#_11-3-核心指标" aria-label="Permalink to &quot;11.3 核心指标&quot;">​</a></h3><ul><li>从场景节拍到“被接受的 1000 字正文”的中位耗时；</li><li>候选接受率与接受后修改比例；</li><li>每 1 万字的模型成本；</li><li>每 1 万字发现/漏掉的连续性问题数；</li><li>用户主动打开上下文预览的比例；</li><li>7 天后是否继续在同一项目写作；</li><li>导出后返工和数据恢复是否可靠。</li></ul><h2 id="_12-实施建议" tabindex="-1">12. 实施建议 <a class="header-anchor" href="#_12-实施建议" aria-label="Permalink to &quot;12. 实施建议&quot;">​</a></h2><h3 id="_12-1-推荐顺序" tabindex="-1">12.1 推荐顺序 <a class="header-anchor" href="#_12-1-推荐顺序" aria-label="Permalink to &quot;12.1 推荐顺序&quot;">​</a></h3><ol><li><strong>数据与存储先行</strong>：项目、卷章场景、正文文件、快照和原子保存。</li><li><strong>编辑闭环</strong>：项目树、正文编辑、选区、自动保存和版本回退。</li><li><strong>上下文编译器</strong>：先支持固定来源和可视化预算，再接复杂检索。</li><li><strong>三种 AI 动作</strong>：节拍起草、续写、选区重写。</li><li><strong>候选与差异</strong>：这是建立信任的关键，不能推迟到“以后”。</li><li><strong>派生记忆</strong>：摘要、事实候选、过期检测。</li><li><strong>连续性审校</strong>：在真实多章项目上验证，而不是只写单元演示。</li></ol><h3 id="_12-2-粗略工作量" tabindex="-1">12.2 粗略工作量 <a class="header-anchor" href="#_12-2-粗略工作量" aria-label="Permalink to &quot;12.2 粗略工作量&quot;">​</a></h3><p>以一名熟悉 AIO Hub 的工程师为基准：</p><ul><li>技术原型：约 2-3 周，可完成项目存储、基础编辑、上下文预览和一次候选生成。</li><li>可供真实作者连续使用的桌面 MVP：约 6-10 周。</li><li>P1 的连续性、伏笔、风格和导入体系：需要在 MVP 使用数据上继续迭代，不建议预先承诺固定周期。</li></ul><p>工作量最大的部分预计是编辑器状态、文件版本和上下文失效传播，而不是 LLM 请求。</p><h3 id="_12-3-最终建议" tabindex="-1">12.3 最终建议 <a class="header-anchor" href="#_12-3-最终建议" aria-label="Permalink to &quot;12.3 最终建议&quot;">​</a></h3><p>立即进入一个受控垂直切片，但设置三条硬边界：</p><ol><li>正文是作品文件，不是聊天消息；</li><li>AI 修改必须可预览、可比较、可撤销；</li><li>模型选择和成本属于项目配置，不属于写死的产品逻辑。</li></ol><p>若垂直切片能让真实作者完成连续两章，并在成本、可控性和前文一致性上明显优于直接使用通用聊天，则值得扩展为 AIO Hub 的正式专精模块。</p><h2 id="_13-资料来源" tabindex="-1">13. 资料来源 <a class="header-anchor" href="#_13-资料来源" aria-label="Permalink to &quot;13. 资料来源&quot;">​</a></h2><h3 id="aio-hub-内部资料" tabindex="-1">AIO Hub 内部资料 <a class="header-anchor" href="#aio-hub-内部资料" aria-label="Permalink to &quot;AIO Hub 内部资料&quot;">​</a></h3><ul><li><a href="./../../src/tools/llm-chat/ARCHITECTURE"><code>src/tools/llm-chat/ARCHITECTURE.md</code></a></li><li><a href="./../../src/tools/knowledge-base/ARCHITECTURE"><code>src/tools/knowledge-base/ARCHITECTURE.md</code></a></li><li><a href="./../../src/tools/st-worldbook-manager/ARCHITECTURE"><code>src/tools/st-worldbook-manager/ARCHITECTURE.md</code></a></li><li><a href="./llm-provider-adapter-sharing-investigation"><code>docs/Plan/llm-provider-adapter-sharing-investigation.md</code></a></li></ul><h3 id="官方产品与定价页面" tabindex="-1">官方产品与定价页面 <a class="header-anchor" href="#官方产品与定价页面" aria-label="Permalink to &quot;官方产品与定价页面&quot;">​</a></h3><ul><li><a href="https://www.novelcrafter.com/" target="_blank" rel="noreferrer">Novelcrafter 产品页</a></li><li><a href="https://www.novelcrafter.com/pricing" target="_blank" rel="noreferrer">Novelcrafter 定价</a></li><li><a href="https://www.sudowrite.com/" target="_blank" rel="noreferrer">Sudowrite 产品页</a></li><li><a href="https://www.sudowrite.com/pricing" target="_blank" rel="noreferrer">Sudowrite 定价</a></li><li><a href="https://novelai.net/" target="_blank" rel="noreferrer">NovelAI 产品与 Writer 套餐</a></li><li><a href="https://write.qq.com/portal/advertising" target="_blank" rel="noreferrer">阅文作家助手桌面端</a></li><li><a href="https://www.feelfish.com/zh" target="_blank" rel="noreferrer">FeelFish 小说写作 AI 智能体</a></li><li><a href="https://zuojia.baidu.com/" target="_blank" rel="noreferrer">百度作家平台</a></li><li><a href="https://platform.kimi.com/docs/pricing/chat" target="_blank" rel="noreferrer">Kimi API 模型推理价格说明</a></li><li><a href="https://platform.kimi.com/docs/pricing/chat-k3" target="_blank" rel="noreferrer">Kimi K3 定价</a></li><li><a href="https://platform.kimi.com/docs/pricing/chat-k26" target="_blank" rel="noreferrer">Kimi K2.6 定价</a></li><li><a href="https://platform.kimi.com/docs/pricing/chat-k25" target="_blank" rel="noreferrer">Kimi K2.5 定价</a></li><li><a href="https://api-docs.deepseek.com/quick_start/pricing" target="_blank" rel="noreferrer">DeepSeek API 模型与定价</a></li></ul>`,67))])}const f=r(p,[["render",u]]);export{k as __pageData,f as default};
